function.body:
-- Logistice
    v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';
    v_Result NUMBER:=1; -- 0=failure
    v_Amount NUMBER:=0; -- 0=failure
    v_AmountAvailable NUMBER:=0; 
    v_AmountUsed NUMBER:=0; 
    v_AmountBalance NUMBER:=0; 
    v_Line_ID VARCHAR2(32);
    v_Record_ID VARCHAR2(32);
    v_User_ID VARCHAR2(32):='0';

    TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Bpartner RECORD;
    Cur_Record RECORD;
    Cur_Lines RECORD;
    Cur_LineReconcile RECORD;

BEGIN

    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || P_Instance_ID);
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'Y', NULL, NULL);

    BEGIN --BODY
        -- Get Parameters
        v_ResultStr:='ReadingParameters';
        FOR Cur_Parameter IN (
            SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date
            FROM AD_PInstance i
                LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID
            WHERE i.AD_PInstance_ID = P_Instance_ID
            ORDER BY p.SeqNo
        ) LOOP
            v_Record_ID := Cur_Parameter.Record_ID;
            v_User_ID := Cur_Parameter.AD_User_ID;
        END LOOP; -- Get Parameter

        SELECT * INTO Cur_Record FROM sdc_debitcollect WHERE sdc_debitcollect_id = v_Record_ID;

        UPDATE sdc_dc_propocollect 
        SET isreconciled ='N', amount_paid = 0, referenceno = null, ispaid='N', description = null
        WHERE sdc_debitcollect_id = v_Record_ID AND isreconciled='Y';

        DELETE FROM sdc_dc_detail WHERE sdc_debitcollect_id = v_Record_ID;

        FOR Cur_Lines IN (
            SELECT * 
            FROM sdc_dc_confirmations 
            WHERE sdc_debitcollect_id =v_Record_ID
            ORDER BY customer
        ) LOOP
            v_AmountAvailable := Cur_Lines.outstandingamt;
            IF Cur_Record.typeload IN ('RPH') THEN 
                FOR Cur_LineReconcile IN (
                    SELECT * 
                    FROM sdc_dc_propocollect p
                    WHERE p.c_bpartner_id = Cur_Lines.c_bpartner_id
                    AND sdc_debitcollect_id = v_Record_ID
                    AND (isreconciled='N' OR COALESCE(outstandingamt,0) <> COALESCE(amount_paid,0))
                    ORDER BY documentno, duedate
                ) LOOP
                    v_AmountBalance := COALESCE(Cur_LineReconcile.outstandingamt,0) - COALESCE(Cur_LineReconcile.amount_paid,0);

                    IF COALESCE(v_AmountAvailable,0) = COALESCE(v_AmountBalance,0) THEN 
                        v_AmountUsed := COALESCE(v_AmountBalance,0);
                        v_AmountAvailable := 0;
                    elsif COALESCE(v_AmountAvailable,0) > COALESCE(v_AmountBalance,0) THEN
                        v_AmountUsed := COALESCE(v_AmountBalance,0);
                        v_AmountAvailable := COALESCE(v_AmountAvailable,0) - COALESCE(v_AmountBalance,0);
                    elsif COALESCE(v_AmountAvailable,0) < COALESCE(v_AmountBalance,0) THEN
                        v_AmountUsed := COALESCE(v_AmountAvailable,0);
                        v_AmountAvailable := 0;
                    END IF;

                    -- Update 
                    UPDATE sdc_dc_propocollect SET isreconciled ='Y' 
                    , updatedby = v_User_ID
                    , updated =  now()
                    -- , referenceno = Cur_Lines.referenceno
                    , amount_paid = COALESCE(amount_paid,0) + COALESCE(v_AmountUsed,0)
                    WHERE sdc_debitcollect_id = v_Record_ID 
                    AND sdc_dc_propocollect_id = Cur_LineReconcile.sdc_dc_propocollect_id;

                    --Create line detail
                    INSERT INTO sdc_dc_detail(
                    sdc_dc_detail_id, ad_client_id, ad_org_id, createdby, 
                    updatedby, sdc_debitcollect_id, sdc_dc_propocollect_id, 
                    c_bpartner_id, fin_payment_schedule_id, referenceno, outstandingamt)
                    VALUES (get_uuid(), Cur_LineReconcile.ad_client_id, Cur_LineReconcile.ad_org_id, v_User_ID, 
                    v_User_ID, Cur_LineReconcile.sdc_debitcollect_id, Cur_LineReconcile.sdc_dc_propocollect_id, 
                    Cur_LineReconcile.c_bpartner_id, Cur_LineReconcile.fin_payment_schedule_id, Cur_Lines.referenceno, v_AmountUsed);

                    IF COALESCE(v_AmountAvailable,0) = 0 THEN 
                        EXIT;
                    END IF;
                END LOOP; -- Get Cur_LineReconcile
            END IF;

            IF Cur_Record.typeload NOT IN ('RPH') THEN 
                IF Cur_Record.condition IN ('AC') THEN 

                    SELECT SUM(p.outstandingamt) 
                    INTO v_Amount
                    FROM sdc_dc_propocollect p
                    WHERE p.c_bpartner_id = Cur_Lines.c_bpartner_id
                    AND sdc_debitcollect_id = v_Record_ID
                    AND isreconciled='N';

                    IF v_Amount = Cur_Lines.outstandingamt THEN 
                        UPDATE sdc_dc_propocollect SET isreconciled ='Y'
                        , updatedby=v_User_ID
                        , referenceno=Cur_Lines.referenceno
                        WHERE sdc_debitcollect_id = v_Record_ID 
                        AND c_bpartner_id = Cur_Lines.c_bpartner_id;
                    END IF;

                END IF;

                IF Cur_Record.condition IN ('ALL','MO') THEN 
                    FOR Cur_LineReconcile IN (
                        SELECT sdc_dc_propocollect_id 
                        FROM sdc_dc_propocollect p
                        WHERE p.c_bpartner_id = Cur_Lines.c_bpartner_id
                        AND outstandingamt = Cur_Lines.outstandingamt
                        AND sdc_debitcollect_id = v_Record_ID
                        AND isreconciled='N'
                        ORDER BY documentno, duedate
                    ) LOOP
                        -- Update 
                        UPDATE sdc_dc_propocollect SET isreconciled ='Y' 
                        , updatedby=v_User_ID
                        , referenceno=Cur_Lines.referenceno
                        WHERE sdc_debitcollect_id = v_Record_ID 
                        AND sdc_dc_propocollect_id = Cur_LineReconcile.sdc_dc_propocollect_id;
                        EXIT;
                    END LOOP; -- Get Cur_LineReconcile
                END IF;
            END IF;

        END LOOP; -- Get Cur_Lines

        DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message);
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', v_Result, v_Message);

        RETURN;
    END; --BODY

    EXCEPTION WHEN OTHERS THEN
        v_ResultStr:= '@ERROR=' || SQLERRM;
        DBMS_OUTPUT.PUT_LINE( v_ResultStr) ;
        ROLLBACK;
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', 0, v_ResultStr);
END SDC_RECONCILE_DATA
